{"output":"import { useCallback, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

export type QueryFilters = Record<string, string | string[] | undefined>;
export type ChangeQueryFilter<T> = (
  filterKey: keyof T,
  filterValue: string | string[] | undefined
) => void;
export type ChangeQueryFilters = (filters: QueryFilters) => void;

export const useQueryFilters = <T>(...filterKeys: (keyof T)[]) => {
  const { search } = useLocation();
  const navigate = useNavigate();

  const query = useMemo(() => new URLSearchParams(search), [search]);
  const queryFilters = useMemo(
    () =>
      filterKeys.reduce(
        (obj, f) => ({ ...obj, [f]: query.get(f.toString()) ?? undefined }),
        {} as Partial<T>
      ),
    [filterKeys, query]
  );

  const setFilter = useCallback(
    (filterKey: string, filterValue?: string | string[]) => {
      if (!filterValue) {
        query.delete(filterKey);
      } else {
        const stringValue = Array.isArray(filterValue) ? filterValue.join(',') : filterValue;
        query.set(filterKey, stringValue);
      }
    },
    [query]
  );

  const pushNewQuery = useCallback(() => {
    query.set('page', '1');
    navigate({ search: query.toString() });
  }, [navigate, query]);

  const changeQueryFilter = useCallback(
    (filterKey: keyof T, filterValue: string | string[] | undefined) => {
      setFilter(filterKey.toString(), filterValue);
      pushNewQuery();
    },
    [setFilter, pushNewQuery]
  );

  const changeQueryFilters = useCallback(
    (filters: Record<string, string | string[] | undefined>) => {
      Object.entries(filters).forEach(([key, value]) => {
        setFilter(key, value);
      });
      pushNewQuery();
    },
    [setFilter, pushNewQuery]
  );

  return { changeQueryFilter, changeQueryFilters, query, queryFilters };
};
